const csvText = $json.body || '';
const lines = csvText.trim().split('\n');
if (!lines.length) {
  return [{ json: { status: 'BLOCKED', missingPatientId: 0, missingReadmission: 0, sentinelBill: 0, message: 'Incoming file is empty.' } }];
}

const headers = lines[0].split(',');
const idx = (key) => headers.indexOf(key);
const iPatient = idx('patient_id');
const iReadmit = idx('readmission_30d');
const iBill = idx('total_bill_usd');
const iDept = idx('department');
const iDischarge = idx('discharge_date');
const iAge = idx('age');
const iLos = idx('length_of_stay');
const iPrev = idx('prev_admissions_12m');
const iMeds = idx('num_medications');

let missingPatientId = 0;
let missingReadmission = 0;
let sentinelBill = 0;

const rows = [];
for (let r = 1; r < lines.length; r++) {
  const cols = lines[r].split(',');
  if (!cols[iPatient]) missingPatientId += 1;
  if (!cols[iReadmit]) missingReadmission += 1;
  if ((cols[iBill] || '').trim() === '-9999') sentinelBill += 1;
  rows.push(cols);
}

if (missingPatientId > 0 || missingReadmission > 0 || sentinelBill > 0) {
  return [{
    json: {
      status: 'BLOCKED',
      missingPatientId,
      missingReadmission,
      sentinelBill
    }
  }];
}

const now = new Date();
const yesterday = new Date(now.getFullYear(), now.getMonth(), now.getDate() - 1);
const ymd = yesterday.toISOString().slice(0, 10);

const riskRows = [];
let high = 0;
let medium = 0;
let low = 0;

for (const cols of rows) {
  if ((cols[iDischarge] || '').trim() !== ymd) continue;

  const age = Number(cols[iAge] || 0);
  const los = Number(cols[iLos] || 0);
  const prev = Number(cols[iPrev] || 0);
  const meds = Number(cols[iMeds] || 0);
  const dept = cols[iDept] || 'Unknown';

  const deptWeight = {
    'Cardiology': 0.12,
    'Oncology': 0.14,
    'Orthopedics': 0.09,
    'Neurology': 0.1,
    'General Medicine': 0.11
  };

  let p = 0.08 + (prev * 0.09) + (los >= 10 ? 0.08 : 0) + (meds >= 12 ? 0.06 : 0) + (age >= 75 ? 0.05 : 0) + (deptWeight[dept] || 0.08);
  p = Math.min(0.95, Math.max(0.02, p));

  let risk = 'Low';
  if (p >= 0.65) risk = 'High';
  else if (p >= 0.4) risk = 'Medium';

  if (risk === 'High') high += 1;
  else if (risk === 'Medium') medium += 1;
  else low += 1;

  if (risk !== 'High') continue;

  const priority = prev >= 2 ? 'URGENT' : 'STANDARD';
  const note = `Patient is High risk mainly due to prior admissions (${prev}) and length of stay (${los} days). Complete coordinator phone follow-up within 48 hours.`;

  riskRows.push({
    patient_id: cols[iPatient],
    department: dept,
    intervention_note: note,
    alert_priority: priority,
  });
}

const urgentRows = riskRows.filter((r) => r.alert_priority === 'URGENT');

if (!urgentRows.length) {
  return [{
    json: {
      status: 'OK',
      high,
      medium,
      low,
      urgentCount: 0,
      urgent_line: 'No URGENT patients today.'
    }
  }];
}

return urgentRows.map((row) => ({
  json: {
    status: 'OK',
    high,
    medium,
    low,
    urgentCount: urgentRows.length,
    patient_id: row.patient_id,
    department: row.department,
    urgent_line: `\u26a0\ufe0f Patient ${row.patient_id} \u2014 ${row.department} \u2014 ${String(row.intervention_note).split('. ')[0]}.`
  }
}));
